payload.raw:
{
  "layout": "timeline",
  "title": "创新设计",
  "events": [
    {
      "date": "第1-2月",
      "title": "硬件攻坚",
      "description": "完成传感器微结构设计、材料制备与标定。基于仿水膜-鱼网结构的液态金属-聚氨酯复合材料，构建融合光纤与IMU的混合传感架构，实现0.1mm级空间分辨率。配置2名硬件工程师与1名材料研究员，依托柔性材料合成设备与高精度信号采集平台，预算22万元。"
    },
    {
      "date": "第3月",
      "title": "算法开发",
      "description": "开发轻量化手势识别分层模型与多模态融合协议。采用分层CNN-LSTM融合架构结合自适应滑动窗口分割，显著提升复杂工况下识别准确率至98.2%以上。配置3名算法工程师与1名数据标注员，使用GPU服务器与仿真环境进行训练，预算18万元。"
    },
    {
      "date": "第4月",
      "title": "系统集成",
      "description": "进行软硬件联调并嵌入触觉反馈模块。集成多模态交互协议栈，嵌入微型电磁致动器阵列与半导体温控模块，实现压力/温度参数的微秒级精准调控。配置2名全栈工程师与2名测试工程师，利用多模态测试舱与合作设备接口进行调试，预算15万元。"
    },
    {
      "date": "第5-6月",
      "title": "场景验证优化",
      "description": "依托合作企业平台（如H-Box全息舱、李未可眼镜）开展工业级远程操控、虚拟实训等多场景压力测试。收集用户体验反馈进行迭代优化，形成可复用的交互标准接口。配置1名产品经理与2名场景测试员，使用远程操控实训场地与反馈采集系统，预算15万元。"
    }
  ]
}

